from dataclasses import dataclass, field
from typing import Literal, Optional

GateOutcome = Literal["PASS", "KILL", "DEFER", "CONDITIONAL_PASS"]

@dataclass
class FeasibilityGateResult:
    gate: str
    outcome: GateOutcome
    score: Optional[float]          # None for binary gates
    threshold: Optional[float]
    blocking_reasons: list[str] = field(default_factory=list)
    conditions: list[str] = field(default_factory=list)  # for CONDITIONAL_PASS

    def passed(self) -> bool:
        return self.outcome in ("PASS", "CONDITIONAL_PASS")

    def __str__(self) -> str:
        s = f"[{self.gate}] {self.outcome}"
        if self.score is not None:
            s += f" (score={self.score:.2f}, threshold={self.threshold:.2f})"
        if self.blocking_reasons:
            s += "\n  Blockers: " + "; ".join(self.blocking_reasons)
        if self.conditions:
            s += "\n  Conditions: " + "; ".join(self.conditions)
        return s


@dataclass
class UseCaseGateAssessment:
    use_case: str
    # Gate 1 inputs
    strategic_fit_score: float        # 1–5: alignment to org strategy
    has_hard_legal_blocker: bool      # known legal prohibition
    # Gate 2 inputs (feasibility)
    tech_feasibility_score: float     # 1–5 composite
    data_readiness_score: float       # 1–5 composite
    skills_feasibility_score: float   # 1–5
    # Gate 3 inputs (business case)
    risk_adjusted_npv_m: float        # millions; negative = value destruction
    payback_months: int
    # Gate 4 inputs (ethics/compliance)
    regulatory_risk: Literal["LOW", "MEDIUM", "HIGH", "BLOCKER"]
    bias_risk: Literal["LOW", "MEDIUM", "HIGH"]

    def run_gate_1(self) -> FeasibilityGateResult:
        """Quick screen: strategic alignment + hard blockers."""
        if self.has_hard_legal_blocker:
            return FeasibilityGateResult(
                gate="Gate 1: Quick Screen", outcome="KILL", score=None, threshold=None,
                blocking_reasons=["Known legal prohibition — requires legal redesign before resubmission"],
            )
        if self.strategic_fit_score < 2.5:
            return FeasibilityGateResult(
                gate="Gate 1: Quick Screen", outcome="KILL", score=self.strategic_fit_score, threshold=2.5,
                blocking_reasons=["Strategic fit below minimum threshold"],
            )
        return FeasibilityGateResult(
            gate="Gate 1: Quick Screen", outcome="PASS",
            score=self.strategic_fit_score, threshold=2.5,
        )

    def run_gate_2(self) -> FeasibilityGateResult:
        """Feasibility gate: tech + data + skills composite."""
        composite = (
            self.tech_feasibility_score * 0.40 +
            self.data_readiness_score   * 0.40 +
            self.skills_feasibility_score * 0.20
        )
        blockers = []
        conditions = []
        if self.tech_feasibility_score < 2.0:
            blockers.append(f"Tech feasibility critically low ({self.tech_feasibility_score}/5)")
        if self.data_readiness_score < 2.0:
            blockers.append(f"Data readiness critically low ({self.data_readiness_score}/5)")
        if blockers:
            return FeasibilityGateResult(
                gate="Gate 2: Feasibility", outcome="KILL",
                score=composite, threshold=3.0, blocking_reasons=blockers,
            )
        if composite < 3.0:
            return FeasibilityGateResult(
                gate="Gate 2: Feasibility", outcome="DEFER",
                score=composite, threshold=3.0,
                blocking_reasons=["Composite feasibility below proceed threshold — address identified gaps"],
            )
        if composite < 3.5:
            conditions = ["Document infrastructure gaps with owner and resolution date before build starts"]
        return FeasibilityGateResult(
            gate="Gate 2: Feasibility",
            outcome="CONDITIONAL_PASS" if conditions else "PASS",
            score=composite, threshold=3.0, conditions=conditions,
        )

    def run_gate_3(self) -> FeasibilityGateResult:
        """Business case gate: risk-adjusted NPV and payback period."""
        blockers, conditions = [], []
        if self.risk_adjusted_npv_m < 0:
            return FeasibilityGateResult(
                gate="Gate 3: Business Case", outcome="KILL",
                score=self.risk_adjusted_npv_m, threshold=0.0,
                blocking_reasons=["Negative risk-adjusted NPV — value destruction"],
            )
        if self.risk_adjusted_npv_m < 0.5:
            blockers.append(f"NPV £{self.risk_adjusted_npv_m:.1f}M below minimum threshold £0.5M")
        if self.payback_months > 24:
            blockers.append(f"Payback {self.payback_months} months exceeds 24-month maximum")
        if blockers:
            return FeasibilityGateResult(
                gate="Gate 3: Business Case", outcome="DEFER",
                score=self.risk_adjusted_npv_m, threshold=0.5, blocking_reasons=blockers,
            )
        return FeasibilityGateResult(
            gate="Gate 3: Business Case", outcome="PASS",
            score=self.risk_adjusted_npv_m, threshold=0.5,
        )

    def run_gate_4(self) -> FeasibilityGateResult:
        """Ethics and compliance gate."""
        if self.regulatory_risk == "BLOCKER":
            return FeasibilityGateResult(
                gate="Gate 4: Ethics/Compliance", outcome="KILL",
                score=None, threshold=None,
                blocking_reasons=["Regulatory blocker — requires legal/compliance redesign"],
            )
        conditions = []
        if self.regulatory_risk == "HIGH":
            conditions.append("Legal review and documented compliance sign-off required before go-live")
        if self.bias_risk == "HIGH":
            conditions.append("Pre-deployment bias audit required; remediation plan must be approved")
        return FeasibilityGateResult(
            gate="Gate 4: Ethics/Compliance",
            outcome="CONDITIONAL_PASS" if conditions else "PASS",
            score=None, threshold=None, conditions=conditions,
        )

    def run_all_gates(self) -> list[FeasibilityGateResult]:
        results = []
        for run_gate in (self.run_gate_1, self.run_gate_2, self.run_gate_3, self.run_gate_4):
            result = run_gate()
            results.append(result)
            if not result.passed():
                break  # stop at first kill/defer
        return results

    def final_outcome(self) -> str:
        results = self.run_all_gates()
        for r in results:
            if r.outcome in ("KILL", "DEFER"):
                return r.outcome
        conditions = [c for r in results for c in r.conditions]
        return "CONDITIONAL_PASS" if conditions else "PASS"


# FNOL classification use case
fnol = UseCaseGateAssessment(
    use_case="FNOL Auto-Classification",
    strategic_fit_score=4.5,
    has_hard_legal_blocker=False,
    tech_feasibility_score=4.0,
    data_readiness_score=4.0,
    skills_feasibility_score=3.5,
    risk_adjusted_npv_m=1.8,
    payback_months=14,
    regulatory_risk="MEDIUM",
    bias_risk="LOW",
)
print(f"=== {fnol.use_case} ===")
for r in fnol.run_all_gates():
    print(r)
print(f"Final: {fnol.final_outcome()}")

print()

# Claims agent with compliance blocker
claims_agent = UseCaseGateAssessment(
    use_case="Automated Claims Settlement Agent",
    strategic_fit_score=4.0,
    has_hard_legal_blocker=False,
    tech_feasibility_score=2.5,
    data_readiness_score=3.5,
    skills_feasibility_score=2.0,
    risk_adjusted_npv_m=3.2,
    payback_months=20,
    regulatory_risk="BLOCKER",   # FCA rules on automated financial decisions
    bias_risk="HIGH",
)
print(f"=== {claims_agent.use_case} ===")
for r in claims_agent.run_all_gates():
    print(r)
print(f"Final: {claims_agent.final_outcome()}")
